############################
# ALL-IN-ONE BSOD SHUTDOWN #
############################

import time
import random
import sys
import os
import threading
import subprocess
import tkinter as tk

# =========================
# HACK SCREEN (CONSOLE)
# =========================

def clear_screen():
    os.system('cls' if os.name == 'nt' else 'clear')


def fake_hacking_screen():
    clear_screen()
    print("Connecting to the mainframe...")
    time.sleep(0.7)
    print("Authentication required...")
    time.sleep(0.7)

    characters = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ1234567890!@#$%^&*()_+"

    for _ in range(300):
        line = ''.join(random.choice(characters) for _ in range(random.randint(60, 80)))
        sys.stdout.write(f"\n{line}")
        sys.stdout.flush()
        time.sleep(0.01)

    steps = [
        "\n================================================================================",
    ]

    for step in steps:
        sys.stdout.write(step)
        sys.stdout.flush()

        for _ in range(60):
            sys.stdout.write(".")
            sys.stdout.flush()
            time.sleep(0.04)

        sys.stdout.write(" [COMPLETED]\n")
        sys.stdout.flush()

    time.sleep(1)
    print("\nACCESS GRANTED")
    print("Welcome.")
    time.sleep(1)

# =========================
# BSOD UI
# =========================

def show_bsod():

    root = tk.Tk()
    root.attributes("-fullscreen", True)
    root.attributes("-topmost", True)
    root.configure(bg="#0078D7")
    root.config(cursor="none")

    main = tk.Frame(root, bg="#0078D7")
    main.pack(fill="both", expand=True, padx=120, pady=80)

    left = tk.Frame(main, bg="#0078D7")
    left.pack(side="left", anchor="nw")

    tk.Label(
        left,
        text=":(",
        fg="white",
        bg="#0078D7",
        font=("Segoe UI", 120)
    ).pack(anchor="w")

    tk.Label(
        left,
        text=(
            "Your PC ran into a problem and needs to restart. We're\n"
            "just collecting some error info, and then we'll restart for\n"
            "you."
        ),
        fg="white",
        bg="#0078D7",
        font=("Segoe UI", 30),
        justify="left"
    ).pack(anchor="w", pady=(10, 30))

    progress_label = tk.Label(
        left,
        text="0% complete",
        fg="white",
        bg="#0078D7",
        font=("Segoe UI", 30)
    )
    progress_label.pack(anchor="w", pady=(0, 40))

    info_row = tk.Frame(left, bg="#0078D7")
    info_row.pack(anchor="w")

    qr_data = """
    
    """

    qr_photo = tk.PhotoImage(data=qr_data)
    
    factor = 1
    qr_photo = qr_photo.zoom(factor, factor)

    label = tk.Label(info_row, image=qr_photo, bg="#0078D7")
    label.image = qr_photo  # prevent garbage collection
    label.pack(side="left")

    tk.Label(
        info_row,
        text=(
            "For more information about this issue and possible fixes, visit\n"
            "https://www.windows.com/stopcode\n\n"
            "If you call a support person, give them this info:\n"
            "Stop code: CRITICAL_PROCESS_DIED"
        ),
        fg="white",
        bg="#0078D7",
        font=("Segoe UI", 14),
        justify="left",
        wraplength=600
    ).pack(side="left", padx=20)

    # Fake progress animation
    progress = 0

    def update():
        nonlocal progress
        if progress < 100:
            progress += random.randint(10, 20)
            progress = min(progress, 100)
            progress_label.config(text=f"{progress}% complete")
            root.after(1800, update)

    update()
    root.mainloop()


# =========================
# SHUTDOWN TIMER
# =========================

def start_shutdown_timer():
    time.sleep(10)
    #subprocess.run(["shutdown", "/s", "/f", "/t", "0"])


# =========================
# MAIN FLOW
# =========================

if __name__ == "__main__":

    # 1️⃣ Play hack screen
    fake_hacking_screen()

    # 2️⃣ Start 10-second shutdown timer (runs in background)
    threading.Thread(target=start_shutdown_timer, daemon=True).start()

    # 3️⃣ Show BSOD while timer counts down
    show_bsod()
